### 4.3 Token 确认机制（服务端实现）

```typescript
// lib/ai/confirmation-token.ts
import { SignJWT, jwtVerify } from 'jose';

const CONFIRMATION_SECRET = new TextEncoder().encode(
  process.env.AUTH_SECRET + ':confirmation',
);

interface ConfirmationPayload {
  userId: string;
  action: 'create_repair' | 'create_apply';
  params: Record<string, unknown>;
  exp: number;
}

export async function generateConfirmationToken(
  payload: Omit<ConfirmationPayload, 'exp'>,
): Promise<string> {
  return new SignJWT({ ...payload, exp: Math.floor(Date.now() / 1000) + 300 })
    .setProtectedHeader({ alg: 'HS256' })
    .sign(CONFIRMATION_SECRET);
}

export async function verifyConfirmationToken(
  token: string,
  userId: string,
): Promise<ConfirmationPayload | null> {
  try {
    const { payload } = await jwtVerify(token, CONFIRMATION_SECRET, {
      algorithms: ['HS256'],
    });
    if (payload.userId !== userId) return null;
    const used = await isTokenUsed(token);
    if (used) return null;
    await markTokenUsed(token);
    return payload as unknown as ConfirmationPayload;
  } catch {
    return null;
  }
}
```

Token 采用 AUTH_SECRET 派生子密钥签发，5 分钟过期，一次性使用（通过黑名单去重），防 CSRF 和重放攻击。

### 4.4 对话 API 流程（伪代码）

```
POST /api/ai/chat:
  1. 如果请求携带 contextToken:
     → 验证 token 签名 + userId 匹配 + 未使用
     → 根据 payload.action 执行操作（创建工单等）
     → 标记 token 已使用
     → 返回操作结果
     → 结束

  2. 否则（正常对话）:
     → 查询用户上下文（持有资产 + 进行中工单）
     → 组装 system prompt + user message（含 history/message/userContext）
     → 调 callDeepSeek
     → 如果 result.needConfirmation === true:
         → 生成 JWT token
         → 返回 { reply, needConfirmation, confirmationToken, pendingAction }
       → 否则：
         → 直接返回 { reply, needConfirmation: false }
```

